{
    "fish_per_trip_sled_dogs": {"Type": "Scalar (positive number)", "Definition": "Amount of fish that can be transported per trip using sled dogs"},
    "fish_per_trip_trucks": {"Type": "Scalar (positive number)", "Definition": "Amount of fish that can be transported per trip using trucks"},
    "cost_per_trip_sled_dogs": {"Type": "Scalar (positive number)", "Definition": "Cost incurred for one sled dog trip"},
    "cost_per_trip_trucks": {"Type": "Scalar (positive number)", "Definition": "Cost incurred for one truck trip"},
    "budget_limit": {"Type": "Scalar (positive number)", "Definition": "Upper limit on total transportation budget"},
    "num_sled_dog_trips": {"Type": "Integer variable", "Definition": "Number of sled dog trips to be planned"},
    "num_truck_trips": {"Type": "Integer variable", "Definition": "Number of truck trips to be planned"},
    "total_fish_transported": {"Type": "Scalar (non-negative number)", "Definition": "Total amount of fish transported, to be maximized"}
}

{
    "VARIABLES": "num_sled_dog_trips: non-negative integer representing the number of sled dog trips; num_truck_trips: non-negative integer representing the number of truck trips",
    "CONSTRAINTS": "cost_per_trip_sled_dogs * num_sled_dog_trips + cost_per_trip_trucks * num_truck_trips <= budget_limit; num_sled_dog_trips < num_truck_trips",
    "OBJECTIVE": "Maximize: fish_per_trip_sled_dogs * num_sled_dog_trips + fish_per_trip_trucks * num_truck_trips"
}
